sp_widget.client_script:
function KnowledgeArticlesCtrl($scope, spUtil) {
    var c = this;
    c.selectedKb = null;
    c.searchQuery = '';
    c.loading = false;
    c.selectedArticle = null;

    c.selectKb = function(kbSysId) {
        c.selectedKb = kbSysId;
        c.loading = true;
        c.server.get({action: 'loadArticles', kb_sys_id: kbSysId, search: c.searchQuery || ''})
            .then(function(response) {
                c.loading = false;
                if (response.data) {
                    c.data.articles = response.data.articles || [];
                    c.data.hasAccess = response.data.hasAccess !== false;
                }
            }, function() { c.loading = false; });
    };

    c.searchArticles = function() {
        if (!c.selectedKb) return;
        c.loading = true;
        c.server.get({action: 'loadArticles', kb_sys_id: c.selectedKb, search: c.searchQuery || ''})
            .then(function(response) {
                c.loading = false;
                if (response.data) c.data.articles = response.data.articles || [];
            }, function() { c.loading = false; });
    };

    c.openArticle = function(article) {
        c.selectedArticle = article;
        // Increment view count
        c.server.get({action: 'recordView', article_sys_id: article.sys_id});
        // Show modal
        $('#' + c.options.sys_id + ' #articleModal').modal('show');
    };
}

sp_widget.css:
#knowledge-articles { max-width: 800px; margin: 0 auto; padding: 20px; font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif; }
.ka-header { text-align: center; padding: 20px; background: linear-gradient(135deg, #17a2b8 0%, #20c997 100%); color: white; border-radius: 8px; margin-bottom: 20px; box-shadow: 0 4px 15px rgba(0,0,0,0.1); }
.ka-header h2 { margin: 0 0 8px 0; font-size: 22px; font-weight: 300; }
.ka-header p { margin: 0; font-size: 13px; opacity: 0.9; }
.ka-kb-selector { margin-bottom: 15px; }
.ka-kb-selector .btn { border: 1px solid #ddd; border-radius: 4px; padding: 12px 8px; white-space: normal; font-size: 12px; background: #f8f9fa; }
.ka-kb-selector .btn-primary { background: #17a2b8; border-color: #17a2b8; color: white; }
.ka-kb-selector .btn .glyphicon { font-size: 20px; }
.ka-search { margin-bottom: 20px; }
.ka-no-access { max-width: 400px; margin: 30px auto; }
.ka-articles { background: white; border: 1px solid #e0e0e0; border-radius: 8px; padding: 15px; }
.ka-article-item { padding: 10px 0; }
.ka-article-item:hover { background: #f0f9ff; margin: 0 -15px; padding: 10px 15px; border-radius: 6px; }
.ka-article-item hr { margin: 10px 0; }
.ka-article-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 5px; }
.ka-article-title { font-weight: 600; color: #007bff; font-size: 15px; }
.ka-article-meta { font-size: 12px; color: #888; margin-bottom: 8px; }
.ka-article-preview { font-size: 13px; color: #555; line-height: 1.4; }
.ka-detail-meta { font-size: 13px; color: #555; }
.ka-detail-content { font-size: 14px; line-height: 1.6; color: #333; }
.spinner { width: 36px; height: 36px; border: 3px solid #f0f0f0; border-top: 3px solid #17a2b8; border-radius: 50%; animation: spin 1s linear infinite; display: inline-block; }
@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

sp_widget.server_script:
(function() {
    data.knowledgeBases = [];
    data.articles = [];
    data.hasAccess = false;

    var ku = new KnowledgeUtils();

    // Load available KBs
    var kbGr = new GlideRecord('kb_knowledge_base');
    kbGr.addQuery('is_valid', true);
    kbGr.orderBy('order');
    kbGr.query();

    while (kbGr.next()) {
        var kbSysId = kbGr.getUniqueValue();
        // Only show KBs user can access
        if (ku.canViewKb(null, kbSysId)) {
            data.knowledgeBases.push({
                sys_id: kbSysId,
                name: kbGr.getValue('name'),
                label: kbGr.getValue('title'),
                description: kbGr.getValue('description')
            });
        }
    }

    if (input && input.action) {
        switch (input.action) {
            case 'loadArticles':
                var kbId = input.kb_sys_id;
                var search = input.search || '';

                if (kbId) {
                    // Check access
                    data.hasAccess = ku.canViewKb(null, kbId);

                    if (data.hasAccess) {
                        var filters = {};
                        if (search) filters.search = search;

                        var articles = ku.getArticles(kbId, filters);

                        // Reformat for display
                        data.articles = articles.map(function(a) {
                            return {
                                sys_id: a.sys_id,
                                short_description: a.short_description,
                                text: a.text,
                                category: a.category,
                                workflow_state: a.workflow_state,
                                state_label: a.state_label,
                                author: a.author,
                                created_on: a.created_on,
                                updated_on: a.updated_on,
                                views: a.views,
                                kb_name: a.kb_name
                            };
                        });
                    }
                }
                break;

            case 'recordView':
                if (input.article_sys_id) {
                    var gr = new GlideRecord('kb_knowledge');
                    if (gr.get(input.article_sys_id)) {
                        // Increment view counter
                        var views = parseInt(gr.getValue('views') || 0);
                        gr.setValue('views', views + 1);
                        gr.setWorkflow(false); // Skip business rules
                        gr.update();
                    }
                }
                break;
        }
    }
})();
